import{c as a,Q as s,j as n,m as o}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"算法总览与工程师心智","description":"","frontmatter":{},"headers":[],"relativePath":"algorithmLearning/01-算法总览与工程师心智.md","filePath":"algorithmLearning/01-算法总览与工程师心智.md","lastUpdated":1778496697000}'),r={name:"algorithmLearning/01-算法总览与工程师心智.md"};function e(p,t,d,l,i,g){return s(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="算法总览与工程师心智" tabindex="-1">算法总览与工程师心智 <a class="header-anchor" href="#算法总览与工程师心智" aria-label="Permalink to &quot;算法总览与工程师心智&quot;">​</a></h1><p>学算法最大的坑,不是&quot;题不会做&quot;,是<strong>搞错了学习姿势</strong>——把它当竞赛、当八股、当玄学。工程师学算法的目标和 ACM 选手不一样,跟背面试题的人也不一样。这一篇不教任何具体算法,只解决一个前置问题:<strong>你到底为什么要学算法、学到什么程度算够、怎么学最不浪费时间</strong>。</p><blockquote><p>一句话先记住:<strong>工程师的算法,是为了让你写代码时&quot;直觉正确&quot;</strong>——选对数据结构、估对复杂度、读懂别人的代码、在性能出问题时第一反应能定位到&quot;是算法选错了还是实现写挫了&quot;。这个水平离 ACM 金牌远得很,但绝大多数工程师<strong>连这个水平都没到</strong>。</p></blockquote><hr><h2 id="一、工程师为什么要学算法" tabindex="-1">一、工程师为什么要学算法 <a class="header-anchor" href="#一、工程师为什么要学算法" aria-label="Permalink to &quot;一、工程师为什么要学算法&quot;">​</a></h2><p>先破三个最常见的误解。</p><p><strong>误解一:&quot;业务代码用不到算法,学了白学&quot;</strong></p><p>错。业务代码天天用——你只是没意识到。往 HashMap 里塞 key、用 Set 去重、sort 一个数组、写分页、查一棵部门树、做权限继承……这些全是算法和数据结构的直接应用。区别只是:<strong>你知道底层发生了什么,还是当黑盒用</strong>。</p><p>当黑盒用短期能跑,长期会挨打:有一天列表从 100 条变成 100 万条,全表 O(n²) 过滤算出来要 30 秒,你一脸懵。懂的人从一开始就会选对数据结构,根本不会有这个 bug。</p><p><strong>误解二:&quot;算法就是 LeetCode 刷题,刷够 300 题就行&quot;</strong></p><p>错。刷题是练手段,不是目的。<strong>刷完 300 题还写不出高质量业务代码的人遍地都是</strong>——因为他们把每道题当孤立案例背,没抽出可迁移的<strong>心智模型</strong>。正确的顺序是:先建模型(这是 DP / 这是滑窗 / 这是图论),再用刷题巩固模型,<strong>而不是反过来</strong>。</p><p><strong>误解三:&quot;算法是面试用,入职就忘&quot;</strong></p><p>部分对,但有害。面试是查一个人的&quot;底层硬件&quot;——能不能迅速把陌生问题拆成已知模型。入职后不会让你每天手写快排,但<strong>遇到性能问题、设计缓存、做限流、排查慢查询</strong>时,没算法底子的人会全程只能 Google,没自己的判断。</p><hr><h2 id="二、工程师的三个水位线" tabindex="-1">二、工程师的三个水位线 <a class="header-anchor" href="#二、工程师的三个水位线" aria-label="Permalink to &quot;二、工程师的三个水位线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>水位</th><th>能力</th><th>对应场景</th></tr></thead><tbody><tr><td>L1:会用</td><td>知道 HashMap O(1) 查、Array sort O(n log n)</td><td>写业务不写 bug</td></tr><tr><td>L2:会选</td><td>场景一来就知道选什么数据结构、避开 O(n²)</td><td>性能不翻车、Code Review 能看出套路</td></tr><tr><td>L3:会造</td><td>读懂 Redis zset / Kafka 消费者组 / HashMap 红黑树化</td><td>读源码、做架构、解疑难杂症</td></tr></tbody></table><p><strong>本系列的目标是 L2,顺带摸到 L3 的门槛</strong>。L3 往上是 ACM / 做数据库引擎的专属区,绝大多数工程师不需要。</p><p>判断自己在哪个水位,有个简单办法:</p><ul><li>看到一道陌生题,<strong>30 秒内说不出大概类别</strong>(滑窗?DP?BFS?)→ L1 以下</li><li>能说出类别,但<strong>写不出模板</strong>(比如知道是 DP,但定义不出状态)→ L1</li><li>能写出模板,但<strong>边界条件经常错</strong>(比如二分写不对 <code>lo &lt;= hi</code> 和 <code>lo &lt; hi</code>)→ L1.5</li><li>模板写得熟,但<strong>优化想不到</strong>(比如能写 O(n²) 但想不到 O(n) 的单调栈)→ L2</li><li>能看 Linux 内核 / PostgreSQL 源码并读懂里面的数据结构设计 → L3</li></ul><hr><h2 id="三、算法学习的-三层抽象" tabindex="-1">三、算法学习的&quot;三层抽象&quot; <a class="header-anchor" href="#三、算法学习的-三层抽象" aria-label="Permalink to &quot;三、算法学习的&quot;三层抽象&quot;&quot;">​</a></h2><p>学算法最低效的做法是&quot;一道题一道题看题解&quot;。<strong>正确的做法是按抽象层级吃</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    心智模型  ←  可迁移,一辈子管用</span></span>
<span class="line"><span>      ↑</span></span>
<span class="line"><span>    算法范式  ←  一类题的套路</span></span>
<span class="line"><span>      ↑</span></span>
<span class="line"><span>    具体算法  ←  某道题的解法</span></span>
<span class="line"><span>      ↑</span></span>
<span class="line"><span>    代码细节  ←  边界 / 指针 / 下标</span></span></code></pre></div><p><strong>大多数人卡在最底下两层,永远上不去</strong>。上来就背&quot;快排怎么写&quot;,写了 50 遍还是写错,因为没建上面两层:</p><ul><li>你要先理解<strong>分治</strong>是什么(心智模型)</li><li>再理解<strong>分治在排序里怎么用</strong>(算法范式)</li><li>最后才是<strong>快排的具体实现</strong>(具体算法)</li></ul><p>建好了模型,忘了快排怎么写也没关系——你能从分治的心智里<strong>推出来</strong>。这就是为什么有人刷 100 题顶别人 1000 题:<strong>抽象层次不一样</strong>。</p><hr><h2 id="四、选对数据结构-80-的算法功夫" tabindex="-1">四、选对数据结构 = 80% 的算法功夫 <a class="header-anchor" href="#四、选对数据结构-80-的算法功夫" aria-label="Permalink to &quot;四、选对数据结构 = 80% 的算法功夫&quot;">​</a></h2><p>工程师 80% 的&quot;算法感&quot;来自<strong>数据结构选得对</strong>。列个速查表,每一行都是真金白银的经验:</p><table tabindex="0"><thead><tr><th>需求</th><th>首选</th><th>理由</th></tr></thead><tbody><tr><td>按 key 查值</td><td>HashMap</td><td>O(1)</td></tr><tr><td>按顺序遍历 + 按 key 查</td><td>TreeMap(红黑树)</td><td>有序 O(log n)</td></tr><tr><td>去重</td><td>HashSet</td><td>O(1)</td></tr><tr><td>去重 + 有序</td><td>TreeSet</td><td>O(log n)</td></tr><tr><td>先进先出</td><td>Queue / Deque</td><td>O(1)</td></tr><tr><td>后进先出</td><td>Stack / Deque</td><td>O(1)</td></tr><tr><td>总是拿最大 / 最小</td><td>PriorityQueue(堆)</td><td>O(log n)</td></tr><tr><td>按前缀查(自动补全)</td><td>Trie</td><td>O(前缀长度)</td></tr><tr><td>判断某元素有没有见过(允许误判)</td><td>BloomFilter</td><td>超省空间</td></tr><tr><td>范围查询(区间和 / 区间最值)</td><td>前缀和 / 线段树 / 树状数组</td><td>O(log n)</td></tr><tr><td>连通性 / 分组</td><td>并查集</td><td>近 O(1)</td></tr></tbody></table><p><strong>一眼识破</strong>:业务同事告诉你&quot;新用户来了给他打标签,老用户就跳过&quot;,你听到这句就该立刻反应&quot;<strong>HashSet 判存在</strong>&quot;;他说&quot;最近 10 个访问的 url 要缓存&quot;,你立刻想到 &quot;<strong>LRU = HashMap + 双向链表</strong>&quot;。这就是 L2。</p><hr><h2 id="五、算法范式只有八种" tabindex="-1">五、算法范式只有八种 <a class="header-anchor" href="#五、算法范式只有八种" aria-label="Permalink to &quot;五、算法范式只有八种&quot;">​</a></h2><p>工程常用的算法范式没那么多,其实就八种,所有常见题都落在里面:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 双指针 / 滑窗   →  线性遍历 + 两个指针夹</span></span>
<span class="line"><span>2. 二分             →  有序 / 单调性 → O(log n)</span></span>
<span class="line"><span>3. 排序 + 贪心      →  先排后扫,每步最优</span></span>
<span class="line"><span>4. 分治             →  分两半递归合并</span></span>
<span class="line"><span>5. BFS / DFS        →  图与树的遍历</span></span>
<span class="line"><span>6. 动态规划         →  重叠子问题 + 最优子结构</span></span>
<span class="line"><span>7. 回溯             →  DFS + 剪枝,求所有解</span></span>
<span class="line"><span>8. 拓扑 + 并查集    →  特化图算法</span></span></code></pre></div><p><strong>记住这八种,再加上三四种数据结构(哈希 / 堆 / 栈 / 队列),80% 题目有套路可抄</strong>。这就是为什么算法看起来难,其实有上限。</p><hr><h2 id="六、学习路径的三种陷阱" tabindex="-1">六、学习路径的三种陷阱 <a class="header-anchor" href="#六、学习路径的三种陷阱" aria-label="Permalink to &quot;六、学习路径的三种陷阱&quot;">​</a></h2><p><strong>陷阱一:按 LeetCode 编号顺序刷</strong>。题号是随机的,你今天碰到 DP,明天碰到图,后天碰到字符串,大脑一直在切换,建不起任何模型。正确的做法:<strong>按套路分组集中刷</strong>(滑窗类一次刷 10 道,DP 一次刷 15 道)。</p><p><strong>陷阱二:刷完题马上看题解</strong>。这是&quot;伪勤奋&quot;最大的坑。你大脑根本没真正动过,看完题解觉得&quot;哦这样啊&quot;,下次还是不会。<strong>至少想够 30 分钟没思路再看题解</strong>,看完题解也别抄——关电脑自己默写一遍,错了再打开。</p><p><strong>陷阱三:只练不回顾</strong>。刷完就丢,一个月后再看题跟没见过一样。<strong>每十道题整理一个模板</strong>:滑窗模板、二分模板、DP 状态定义模板……这些模板才是你真正带走的东西。</p><hr><h2 id="七、本系列的承诺" tabindex="-1">七、本系列的承诺 <a class="header-anchor" href="#七、本系列的承诺" aria-label="Permalink to &quot;七、本系列的承诺&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不堆公式    →  大 O 只讲直觉,不讲主定理证明</span></span>
<span class="line"><span>不比赛向    →  后缀自动机 / 李超线段树不讲</span></span>
<span class="line"><span>不按题号走  →  按套路分组,每类讲清楚再往下</span></span>
<span class="line"><span>每篇独立    →  每篇看完都有个可带走的模板 / 心智图</span></span></code></pre></div><p><strong>28 篇的硬目标</strong>:</p><ul><li>看完 01-08(心智 + 线性),日常业务代码不再用 O(n²) 写本可 O(n) 的逻辑</li><li>看完 09-22(树图 + 范式),面试白板题不怵,能识别 80% 题的分类</li><li>看完 23-28(工程实战),能自己写限流中间件 / LRU 缓存 / 一致性哈希路由</li></ul><hr><h2 id="八、一句话总结" tabindex="-1">八、一句话总结 <a class="header-anchor" href="#八、一句话总结" aria-label="Permalink to &quot;八、一句话总结&quot;">​</a></h2><blockquote><p><strong>算法不是记忆游戏,是抽象训练</strong>。你不是在背套路,是在把具体问题<strong>抽到已知模型的高度</strong>——然后套路就是结果,不是前提。</p></blockquote><p>下一篇讲复杂度——大 O 到底怎么看、什么时候看均摊、为什么哈希表&quot;平均 O(1) 最坏 O(n)&quot;不是自相矛盾。</p>`,50)])])}const c=a(r,[["render",e]]);export{u as __pageData,c as default};
